import{_ as n,W as t,X as s,Z as e,a1 as o,$ as i,Y as a,G as g}from"./framework-3515e50f.js";const l="/Eddie-Tech-Blog.github.io/assets/image-20221206112643989.png",c="/Eddie-Tech-Blog.github.io/assets/image-20221206112822848.png",d="/Eddie-Tech-Blog.github.io/assets/image-20221206112136402.png",p="/Eddie-Tech-Blog.github.io/assets/image-20221206113122527.png",h="/Eddie-Tech-Blog.github.io/assets/image-20221206114549536.png",u="/Eddie-Tech-Blog.github.io/assets/image-20221206114605315.png",m={},f=e("h1",{id:"zookeeper",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#zookeeper","aria-hidden":"true"},"#"),o(" Zookeeper")],-1),_=e("figure",null,[e("img",{src:l,alt:"image-20221206112643989",tabindex:"0",loading:"lazy"}),e("figcaption",null,"image-20221206112643989")],-1),b={href:"https://zookeeper.apache.org/",target:"_blank",rel:"noopener noreferrer"},k=a('<p><strong>分布式应用程序协调服务软件</strong></p><figure><img src="'+c+'" alt="image-20221206112822848" tabindex="0" loading="lazy"><figcaption>image-20221206112822848</figcaption></figure><p>ZooKeeper 是 Apache 软件基金会的一个软件项目，它为大型<strong>分布式</strong>计算提供开源的<strong>分布式配置服务</strong>、<strong>同步服务</strong>和<strong>命名注册</strong>。</p><p>ZooKeeper 的架构通过冗余服务实现高可用性。</p><p>Zookeeper 的设计目标是将那些复杂且容易出错的分布式一致性服务封装起来，构成一个高效可靠的原语集，并以一系列简单易用的接口提供给用户使用。</p><p>一个典型的分布式数据一致性的解决方案，分布式应用程序可以基于它实现诸如数据<strong>发布/订阅</strong>、<strong>负载均衡</strong>、<strong>命名服务</strong>、<strong>分布式协调/通知</strong>、<strong>集群管理</strong>、<strong>Master 选举</strong>、<strong>分布式锁</strong>和<strong>分布式队列</strong>等功能。</p><ul><li><strong>命名服务</strong> - 按名称标识集群中的节点。它类似于DNS，但仅对于节点。</li><li><strong>配置管理</strong> - 加入节点的最近的和最新的系统配置信息。</li><li><strong>集群管理</strong> - 实时地在集群和节点状态中加入/离开节点。</li><li><strong>选举算法</strong> - 选举一个节点作为协调目的的leader。</li><li><strong>锁定和同步服务</strong> - 在修改数据的同时锁定数据。此机制可帮助你在连接其他分布式应用程序（如Apache HBase）时进行自动故障恢复。</li><li><strong>高度可靠的数据注册表</strong> - 即使在一个或几个节点关闭时也可以获得数据。</li></ul><p>分布式应用程序提供了很多好处，但它们也抛出了一些复杂和难以解决的挑战。ZooKeeper框架提供了一个完整的机制来克服所有的挑战。竞争条件和死锁使用<strong>故障安全同步方法</strong>进行处理。另一个主要缺点是数据的不一致性，ZooKeeper使用<strong>原子性</strong>解析。</p><h2 id="zookeeper-数据结构" tabindex="-1"><a class="header-anchor" href="#zookeeper-数据结构" aria-hidden="true">#</a> zookeeper 数据结构</h2><p>zookeeper 提供的名称空间非常类似于标准文件系统，key-value 的形式存储。名称 key 由斜线 <strong>/</strong> 分割的一系列路径元素，zookeeper 名称空间中的每个节点都是由一个路径标识</p><figure><img src="'+d+'" alt="image-20221206112136402" tabindex="0" loading="lazy"><figcaption>image-20221206112136402</figcaption></figure><h2 id="相关理论" tabindex="-1"><a class="header-anchor" href="#相关理论" aria-hidden="true">#</a> 相关理论</h2><h3 id="cap理论" tabindex="-1"><a class="header-anchor" href="#cap理论" aria-hidden="true">#</a> CAP理论</h3><p>CAP 理论指出对于一个分布式计算系统来说，<strong>不可能同时满足以下三点</strong>：</p><ul><li><strong>一致性(Consistency)</strong>：在分布式环境中，一致性是指数据在多个副本之间是否能够保持一致的特性，等同于所有节点访问同一份最新的数据副本。在一致性的需求下，当一个系统在数据一致的状态下执行更新操作后，应该保证系统的数据仍然处于一致的状态。</li><li>**可用性(Availability)：**每次请求都能获取到正确的响应，但是不保证获取的数据为最新数据。</li><li>**分区容错性(Partition Tolerance)：**分布式系统在遇到任何网络分区故障的时候，仍然需要能够保证对外提供满足一致性和可用性的服务，除非是整个网络环境都发生了故障。</li></ul><figure><img src="'+p+'" alt="image-20221206113122527" tabindex="0" loading="lazy"><figcaption>image-20221206113122527</figcaption></figure><p>一个分布式系统最多只能同时满足一致性（Consistency）、可用性（Availability）和分区容错性（Partition tolerance）这三项中的两项。</p><p>在这三个基本需求中，最多只能同时满足其中的两项，<strong>P 是必须的</strong>，因此只能在 <strong>CP</strong> 和 <strong>AP</strong> 中选择，<strong>zookeeper 保证的是 CP</strong>，对比 spring cloud 系统中的注册中心 <strong>Eureka 实现的是 AP</strong>。</p><h3 id="base-理论" tabindex="-1"><a class="header-anchor" href="#base-理论" aria-hidden="true">#</a> BASE 理论</h3><p>BASE 是 <mark>Basically Available(基本可用)</mark>、<mark>Soft-state(软状态)</mark> 和 <mark>Eventually Consistent(最终一致性)</mark> 三个短语的缩写。</p><ul><li>**基本可用：**在分布式系统出现故障，允许损失部分可用性（服务降级、页面降级）。</li><li>**软状态：**允许分布式系统出现中间状态。而且中间状态不影响系统的可用性。这里的中间状态是指不同的 data replication（数据备份节点）之间的数据更新可以出现延时的最终一致性。</li><li>**最终一致性：**data replications 经过一段时间达到一致性。</li></ul><p><strong>BASE 理论是对 CAP 中的一致性和可用性进行一个权衡的结果</strong>，理论的核心思想就是：我们无法做到强一致，但每个应用都可以根据自身的业务特点，采用适当的方式来使系统达到最终一致性。</p><h2 id="zookeeper-安装配置" tabindex="-1"><a class="header-anchor" href="#zookeeper-安装配置" aria-hidden="true">#</a> Zookeeper 安装配置</h2><h3 id="linux-安装" tabindex="-1"><a class="header-anchor" href="#linux-安装" aria-hidden="true">#</a> Linux 安装</h3>',24),v={href:"https://zookeeper.apache.org/releases.html",target:"_blank",rel:"noopener noreferrer"},z=a('<figure><img src="'+h+'" alt="image-20221206114549536" tabindex="0" loading="lazy"><figcaption>image-20221206114549536</figcaption></figure><figure><img src="'+u+`" alt="image-20221206114605315" tabindex="0" loading="lazy"><figcaption>image-20221206114605315</figcaption></figure><div class="language-text line-numbers-mode" data-ext="text"><pre class="language-text"><code>[root@192 opt]# tar -zxvf zookeeper-3.4.9.tar.gz #解压缩
$ cd zookeeper-3.4.14 
$ cd conf/ #进去配置文件目录
$ cp zoo_sample.cfg zoo.cfg #复制一份配置文件模板 并命名为zoo.cfg用于启动
$ cd ..
$ cd bin/ #进去到bin目录下
$ sh zkServer.sh start #启动zookeeper
$ sh zkServer.sh status #查看zookeeper状态
$ sh zkCli.sh #启动客户端
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div>`,3);function x(A,y){const r=g("ExternalLinkIcon");return t(),s("div",null,[f,_,e("p",null,[e("a",b,[o("Apache ZooKeeper"),i(r)])]),k,e("p",null,[e("a",v,[o("Apache ZooKeeper"),i(r)])]),z])}const E=n(m,[["render",x],["__file","zookeeper.html.vue"]]);export{E as default};
